const t=JSON.parse('{"key":"v-366d4296","path":"/posts/%E6%B5%8B%E7%BB%98/%E5%9C%B0%E7%90%86%E4%BF%A1%E6%81%AF%E7%B3%BB%E7%BB%9F%EF%BC%88GIS%EF%BC%89.html","title":"地理信息系统（GIS）","lang":"en-US","frontmatter":{"description":"地理信息系统（GIS） 地理信息系统 (GIS) 技术文档 1. 概述 地理信息系统 (Geographic Information System, GIS) 是一种用于采集、存储、管理、分析、展示地理空间数据的计算机系统。它将地理位置信息与属性信息相结合，帮助用户更好地理解空间关系、模式和趋势，从而为决策提供支持。 2. 核心概念 地理空间数据: 描述地球表面要素位置、形状、大小及其相互关系的数据，包括矢量数据和栅格数据两种主要类型。 矢量数据: 用点、线、面等几何图形表示地理要素，例如道路、建筑物、行政边界等。 栅格数据: 用像元阵列表示地理要素，每个像元代表一个区域并存储该区域的属性值，例如卫星影像、数字高程模型等。 属性数据: 描述地理要素特征的数据，例如道路名称、建筑物高度、人口数量等。 空间关系: 地理要素之间的位置关系，例如相邻、包含、相交等。 空间分析: 利用 GIS 工具对地理空间数据进行处理和分析，例如缓冲区分析、叠加分析、网络分析等。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E5%9C%B0%E7%90%86%E4%BF%A1%E6%81%AF%E7%B3%BB%E7%BB%9F%EF%BC%88GIS%EF%BC%89.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"地理信息系统（GIS）"}],["meta",{"property":"og:description","content":"地理信息系统（GIS） 地理信息系统 (GIS) 技术文档 1. 概述 地理信息系统 (Geographic Information System, GIS) 是一种用于采集、存储、管理、分析、展示地理空间数据的计算机系统。它将地理位置信息与属性信息相结合，帮助用户更好地理解空间关系、模式和趋势，从而为决策提供支持。 2. 核心概念 地理空间数据: 描述地球表面要素位置、形状、大小及其相互关系的数据，包括矢量数据和栅格数据两种主要类型。 矢量数据: 用点、线、面等几何图形表示地理要素，例如道路、建筑物、行政边界等。 栅格数据: 用像元阵列表示地理要素，每个像元代表一个区域并存储该区域的属性值，例如卫星影像、数字高程模型等。 属性数据: 描述地理要素特征的数据，例如道路名称、建筑物高度、人口数量等。 空间关系: 地理要素之间的位置关系，例如相邻、包含、相交等。 空间分析: 利用 GIS 工具对地理空间数据进行处理和分析，例如缓冲区分析、叠加分析、网络分析等。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"地理信息系统（GIS）\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"地理信息系统 (GIS) 技术文档","slug":"地理信息系统-gis-技术文档","link":"#地理信息系统-gis-技术文档","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":3.28,"words":983},"filePathRelative":"posts/测绘/地理信息系统（GIS）.md","localizedDate":"August 16, 2025","excerpt":"<h1> 地理信息系统（GIS）</h1>\\n<h2> 地理信息系统 (GIS) 技术文档</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>地理信息系统 (Geographic Information System, GIS) 是一种用于采集、存储、管理、分析、展示地理空间数据的计算机系统。它将地理位置信息与属性信息相结合，帮助用户更好地理解空间关系、模式和趋势，从而为决策提供支持。</p>\\n<p><strong>2. 核心概念</strong></p>\\n<ul>\\n<li><strong>地理空间数据:</strong> 描述地球表面要素位置、形状、大小及其相互关系的数据，包括矢量数据和栅格数据两种主要类型。\\n<ul>\\n<li><strong>矢量数据:</strong> 用点、线、面等几何图形表示地理要素，例如道路、建筑物、行政边界等。</li>\\n<li><strong>栅格数据:</strong> 用像元阵列表示地理要素，每个像元代表一个区域并存储该区域的属性值，例如卫星影像、数字高程模型等。</li>\\n</ul>\\n</li>\\n<li><strong>属性数据:</strong> 描述地理要素特征的数据，例如道路名称、建筑物高度、人口数量等。</li>\\n<li><strong>空间关系:</strong> 地理要素之间的位置关系，例如相邻、包含、相交等。</li>\\n<li><strong>空间分析:</strong> 利用 GIS 工具对地理空间数据进行处理和分析，例如缓冲区分析、叠加分析、网络分析等。</li>\\n</ul>","autoDesc":true}');export{t as data};
